changeSet.sql:
create or replace function gmdb.details_enforce_resource_id_immutable()
returns trigger
language plpgsql
as $$
begin
    if (old.details->>'resourceId') is distinct from (new.details->>'resourceId') then
        raise exception '%s.details->resourceId is not updatable', tg_table_name;
    end if;
    return new;
end;
$$;

create or replace function gmdb.details_default_resource_id()
    returns trigger
    language plpgsql
as $$
begin
    new.details := jsonb_build_object('resourceId', gen_random_uuid())
        || coalesce(new.details, '{}'::jsonb);
    return new;
end;
$$;

create or replace function gmdb.details_default_resource_id()
    returns trigger
    language plpgsql
as $$
begin
    if new.details is not null
        and new.details ? 'resourceId'
        and jsonb_typeof(new.details->'resourceId') = 'null' then
        raise exception '%.details->resourceId must not be null', tg_table_name;
    end if;

    new.details := jsonb_build_object('resourceId', gen_random_uuid())
        || coalesce(new.details, '{}'::jsonb);
    return new;
end;
$$;
